INSERT INTO public.cms_configs VALUES ('e8bd17c4-5634-4631-9877-ad422644861c', 'privacy-policy', '{"banner": {"title": "Chính sách bảo mật", "subtitle": "Chúng tôi cam kết bảo vệ dữ liệu cá nhân của bạn", "backgroundImage": ""}, "content": {"sections": [{"title": "1. Thông tin chúng tôi thu thập", "content": "Chúng tôi thu thập thông tin bạn cung cấp khi đăng ký tài khoản, bao gồm tên, email, và thông tin thanh toán."}, {"title": "2. Cách chúng tôi sử dụng thông tin", "content": "Thông tin được sử dụng để cung cấp và cải thiện dịch vụ, xử lý thanh toán, và giao tiếp với bạn."}], "introTitle": "Chính sách bảo mật Vit IELTS", "introParagraphs": ["Chúng tôi tôn trọng quyền riêng tư của bạn và cam kết bảo vệ dữ liệu cá nhân."]}, "heroImage": ""}', '2026-04-06 04:08:42.538633+00');
