INSERT INTO public.cms_configs VALUES ('05f041a6-da55-498f-8dfa-0b2771e52086', 'footer/cta-banner', '{"title": "Sẵn sàng cho kì thi IELTS máy?", "button": {"link": "/subscription", "text": "Nâng cấp Premium"}, "description": "Đăng ký luyện tập trên giao diện giống phòng thi thật ngay hôm nay!", "backgroundGradient": "linear-gradient(135deg, #D94A56 0%, #E86B75 100%)"}', '2026-04-06 04:33:35.221+00');
INSERT INTO public.cms_configs VALUES ('6ec395b1-5d70-4ec0-ae99-523b0c86da9a', 'header/announcement-bar', '{"items": [{"url": "", "text": "THÔNG BÁO BẢO MẬT - Các bạn có tài khoản Pro vui lòng đổi mật khẩu mới"}, {"url": "", "text": "FORECAST 1.6 - 8.6 Tại Mục Prediction và Mục Sample"}], "enabled": true, "rightLink": {"url": "https://zalo.me/g/edorpy603", "badge": "ZALO", "label": "Nhóm Dự Đoán", "enabled": true}, "textColor": "#ffffff", "settingsIcon": {"url": "", "enabled": false}, "speedSeconds": 120, "backgroundColor": "#cd3d41"}', '2026-06-05 09:36:06.432+00');
INSERT INTO public.cms_configs VALUES ('95819d76-da9e-47c6-b0d9-cd2dc87a1149', 'home/why-choose-us', '{"badge": "Tại sao chọn chúng tôi?", "stats": [{"icon": "/assets/figma/icons/LovedbyStudents.svg", "label": "HỌC VIÊN YÊU THÍCH", "number": "5,000+", "bgColor": "#D94A56"}, {"icon": "/assets/figma/icons/Aim.svg", "label": "HỌC VIÊN ĐẠT AIM", "number": "1,000+", "bgColor": "#219653"}, {"icon": "/assets/figma/icons/Legit.svg", "label": "ĐỀ THI THẬT", "number": "20+", "bgColor": "#5281F9"}, {"icon": "/assets/figma/icons/Goal.svg", "label": "HỌC VIÊN ĐẠT 8.0", "number": "100+", "bgColor": "#FC945A"}], "title": "Luyện thi IELTS Trên Giao Diện Thi Thật", "description": "IPT cung cấp bộ đề thi thật tập trung vào các dạng câu hỏi xuất hiện thường xuyên, chủ đề lặp lại và cấu trúc đề được ghi nhận từ thí sinh thi gần đây, giúp người học luyện tập hiệu quả, tránh học lan man và tiết kiệm thời gian ôn tập."}', '2026-04-06 04:08:42.538633+00');
INSERT INTO public.cms_configs VALUES ('c2d1fca4-24a1-4ba8-a075-9e5c7abe9f32', 'home/hero-banner', '{"cta": {"link": "https://www.vitieltstest.com/ielts-exam-library", "text": "Khám Phá Ngay"}, "title": {"line1": "Vit IELTS", "line2": "Thi", "highlight": "Thử Như Thật"}, "images": {"mascot": "/assets/figma/icons/like 1.png", "screen": "/assets/figma/icons/screen 1.png"}, "subtitle": "Thi thử như thật với giao diện 1:1 và kho đề sát thực tế. Bứt phá band điểm cùng hệ thống giải thích chi tiết.", "checklist": ["Giao diện thi máy", "Cập nhật xu hướng đề", "Chấm chữa chi tiết, tối ưu thời gian"]}', '2026-05-08 10:22:24.583+00');
INSERT INTO public.cms_configs VALUES ('331f7c57-4999-4aa3-845e-09d24a572698', 'home/test-platform-intro', '{"badge": "PREMIUM", "cards": [{"bg": "/assets/figma/icons/Background-1.png", "href": "/ielts-exam-library", "icon": "/assets/figma/icons/book (1) 1.svg", "color": "from-rose-600 to-rose-500", "title": "IELTS Full Test"}, {"bg": "/assets/figma/icons/Background-2.png", "href": "/ielts-practice-library?skill=listening", "icon": "/assets/figma/icons/listen 1.svg", "color": "from-emerald-600 to-emerald-500", "title": "Listening Practice"}, {"bg": "/assets/figma/icons/Background-3.png", "href": "/ielts-practice-library?skill=reading", "icon": "/assets/figma/icons/reading-book 1.svg", "color": "from-orange-600 to-orange-400", "title": "Reading Practice"}, {"bg": "/assets/figma/icons/Background-4.png", "href": "/ielts-writing-sample", "icon": "/assets/figma/icons/copywriting (1) 1.svg", "color": "from-indigo-400 to-indigo-300", "title": "Sample Writing"}, {"bg": "/assets/figma/icons/Background-5.png", "href": "/ielts-speaking-sample", "icon": "/assets/figma/icons/speaking 1.svg", "color": "from-amber-500 to-yellow-400", "title": "Sample Speaking"}, {"bg": "/assets/figma/icons/Background-6.png", "href": "/ielts-prediction", "icon": "/assets/figma/icons/search 1.svg", "color": "from-blue-600 to-blue-500", "title": "Vit IELTS"}], "title": "Khám Phá Kho Đề", "titleHighlight": "Dự Đoán"}', '2026-05-11 16:55:58.118+00');
INSERT INTO public.cms_configs VALUES ('55e8f2fe-4ab2-42b2-a461-44943c742ed4', 'home/testimonials', '{"cta": {"link": "/subscription", "text": "Xem Thêm Phản Hồi"}, "title": "Phản hồi từ học viên", "reviews": [{"name": "Nguyễn Thị Lan", "score": "IELTS 7.0 | L 8.5 | R 8.0", "avatar": "https://cms.vitieltstest.com/media/images/e05277dd7989c84d2a52f88b8cb6433a-1779445539.jpg", "rating": 5, "review": "Giao diện thi rất giống thi thật, giúp mình làm quen trước ngày thi. Mình đã đạt band 7.0 sau 2 tháng luyện tập liên tục."}, {"name": "Phương Anh Sarah", "score": "IELTS 7.5 | L 8.0 | R 8.5", "avatar": "https://cms.vitieltstest.com/media/images/1040g2jo31tc2p9nime5g5nqr2pgg92c38v2bcpo-1779436970.webp", "rating": 5, "review": "Đề thi sát với cấu trúc thật. Mình thích cách chấm điểm tự động, tiết kiệm rất nhiều thời gian ôn luyện."}, {"name": "Võ Hoàng Ngọc Trân", "score": "IELTS 7.5 | L 8.5 | R 7.5", "avatar": "https://cms.vitieltstest.com/media/images/images--19-1779436151.jfif", "rating": 5, "review": "Trang web này giúp mình tập làm quen với format thi thật. Sau khi luyện đủ 30 bài, mình tự tin hơn hẳn khi thi chính thức."}, {"name": "Bùi Thị Thu", "score": "IELTS 8.5 | L 9.0 | R 8.5", "avatar": "https://cms.vitieltstest.com/media/images/avatar-anh-gai-xinh-k5-12-1779437694.webp", "rating": 5, "review": "Phần Listening rất chuẩn, đúng format. Mình từng mua khóa học bên ngoài nhưng giờ luyện ở đây là đủ rồi."}, {"name": "Lý Thanh Sơn", "score": "IELTS 7.5 | L 7.5 | R 8.0", "avatar": "https://cms.vitieltstest.com/media/images/1040g2jo31hqstmfhjue05p4s0e343obrjbctsio-1779437802.webp", "rating": 5, "review": "Rất hài lòng với chất lượng đề. Hệ thống chấm điểm tức thì giúp mình biết ngay điểm yếu để cải thiện."}, {"name": "Đinh Quốc Tuấn", "score": "IELTS 7.5 | L 8.5 | R 7.0", "avatar": "https://cms.vitieltstest.com/media/images/700e00c3493409190f84e3c7d846af88-1779437974.jpg", "rating": 5, "review": "Platform tốt nhất mình từng dùng để luyện IELTS. Reading và Listening đều rất chất lượng, đề đa dạng."}, {"name": "Lê Quốc Bảo", "score": "IELTS 8.0 | L 8.0 | R 9.0", "avatar": "https://cms.vitieltstest.com/media/images/5fcc79716ad80bdc008774de9986ef1f-1779438263.jpg", "rating": 5, "review": "Mình luyện tập mỗi ngày với bộ đề ở đây. Sau 3 tháng đã tăng từ 5.5 lên 6.0, rất hài lòng với kết quả."}, {"name": "Ngô Thị Mai", "score": "IELTS 8.5 | L 7.5 | R 8.5", "avatar": "https://cms.vitieltstest.com/media/images/ea8a279ed6d038da54c2bc61db67f131-1779438331.jpg", "rating": 5, "review": "Giao diện rất thân thiện và chuyên nghiệp. Đề thi bám sát thực tế và cập nhật thường xuyên."}, {"name": "Đinh Văn Khoa", "score": "IELTS 7.5 | L 8.5 | R 7.0", "avatar": "https://cms.vitieltstest.com/media/images/d1fe54e0d64cd11fd80a401433942550-1779438584.jpg", "rating": 5, "review": "Trải nghiệm thi thử rất mượt mà, không khác gì thi thật. Mình đã tăng 1.0 band chỉ sau 2 tháng luyện đề đây."}, {"name": "Vương Thị Liên", "score": "IELTS 7.0 | L 7.0 | R 7.5", "avatar": "https://cms.vitieltstest.com/media/images/1dcb39a82d100c8a0d310ffd17ce4d7e-1779438539.jpg", "rating": 5, "review": "Bộ đề phong phú, giải thích chi tiết. Mình đặc biệt thích tính năng xem lại lỗi sai sau mỗi bài thi."}, {"name": "Đặng Thu Hương", "score": "IELTS 8.0 | L 8.0 | R 7.5", "avatar": "https://cms.vitieltstest.com/media/images/0a93db068358f68557e28bb43db9d906-1779438640.jpg", "rating": 5, "review": "Hệ thống giao diện máy tính rất mượt, đúng với format thi thật. Đặc biệt phần Listening rất chuẩn."}, {"name": "Vũ Thế Dũng", "score": "IELTS 8.0 | L 9.0 | R 9.0", "avatar": "https://cms.vitieltstest.com/media/images/1bd9f912c669b411d1c8cd34c29957b2-1779438680.jpg", "rating": 5, "review": "Luyện đề trên này giúp mình quen với áp lực thời gian. Kết quả thi thật tốt hơn mình mong đợi."}, {"name": "Trịnh Thị Ngọc", "score": "IELTS 8.0 | L 7.5 | R 8.0", "avatar": "https://cms.vitieltstest.com/media/images/a89d9990ff302ad2e5686d7d4ae030e4-1779438716.jpg", "rating": 5, "review": "Mình đã thử nhiều nền tảng luyện IELTS khác nhau. Đây là nơi có đề sát thực nhất và interface đẹp nhất."}, {"name": "Cao Minh Nhật", "score": "IELTS 8.0 | L 7.0 | R 8.0", "avatar": "https://cms.vitieltstest.com/media/images/202770e205ea25d77a7395199ba34162-1779438746.jpg", "rating": 5, "review": "Chất lượng đề thi cao, cập nhật liên tục. Mình học Read và Listen ở đây là chủ yếu và thấy hiệu quả rõ rệt."}, {"name": "Phan Thị Hải", "score": "IELTS 7.5 | L 8.0 | R 7.0", "avatar": "https://cms.vitieltstest.com/media/images/00c3953a03b8252d39f7c0e15d44bc3f-1779438779.jpg", "rating": 5, "review": "Sau khi dùng nền tảng này 3 tháng, mình đạt 7.5 thật sự bất ngờ. Phần thi thật không khác gì luyện ở đây."}], "description": "Trải nghiệm thực tế từ học viên đã luyện đề sát cấu trúc thi thật và làm quen giao diện thi máy trước ngày thi."}', '2026-06-01 04:46:35.985+00');
INSERT INTO public.cms_configs VALUES ('dbb37989-fbc6-4631-9321-85aefc532635', 'ielts-practice-library/banner', '{"reading": {"title": "IELTS Reading Practice", "button": {"link": "/ielts-practice-library?skill=reading", "text": "Bắt đầu luyện tập"}, "description": {"line1": "Luyện tập IELTS Reading với hàng trăm bài tập", "line2": "từ Academic đến General Training.", "line3": ""}, "backgroundColor": "#2D3142"}, "listening": {"title": "IELTS Listening Practice", "button": {"link": "/ielts-practice-library?skill=listening", "text": "Bắt đầu luyện tập"}, "description": {"line1": "Luyện tập IELTS Listening với hàng trăm bài tập", "line2": "từ dễ đến khó, sát đề thi thật nhất.", "line3": ""}, "backgroundColor": "#D94A56"}}', '2026-04-06 04:08:42.538633+00');
INSERT INTO public.cms_configs VALUES ('fe5fe14b-4f1c-44f0-ac76-79a5de552f12', 'terms-of-use', '{"banner": {"title": "Điều khoản sử dụng", "subtitle": "Vui lòng đọc kỹ trước khi sử dụng dịch vụ", "backgroundImage": ""}, "content": {"sections": [{"title": "1. Chấp nhận điều khoản", "content": "Bằng việc truy cập và sử dụng website, bạn đồng ý tuân thủ và bị ràng buộc bởi các điều khoản và điều kiện này."}, {"title": "2. Tài khoản người dùng", "content": "Bạn chịu trách nhiệm bảo mật tài khoản và mật khẩu của mình. Mọi hoạt động trên tài khoản là trách nhiệm của bạn."}], "introTitle": "Điều khoản sử dụng Vit IELTS", "introParagraphs": ["Chào mừng bạn đến với Vit IELTS. Bằng việc sử dụng dịch vụ, bạn đồng ý với các điều khoản sau."]}, "heroImage": ""}', '2026-04-06 04:08:42.538633+00');
INSERT INTO public.cms_configs VALUES ('c45bce6a-a02b-4a13-ba11-f6a74bee2183', 'contact', '{"form": {"nameLabel": "Your name", "buttonText": "Send message", "emailLabel": "Your email address", "errorMessage": "Something went wrong", "messageLabel": "Message", "subjectLabel": "Subject", "successMessage": "Thank you for your message! We will get back to you soon.", "namePlaceholder": "Name", "emailPlaceholder": "Email", "messagePlaceholder": "Message", "subjectPlaceholder": "Subject"}, "banner": {"title": "Contact", "backgroundImage": ""}, "socialLinks": [{"url": "https://www.facebook.com/groups/ielts.practice", "label": "Facebook Group", "iconUrl": "/img-admin/social/facebook.svg", "platform": "facebook", "username": "@ielts.practice"}, {"url": "https://tiktok.com/@ielts.practice", "label": "TikTok", "iconUrl": "/img-admin/social/tiktok.svg", "platform": "tiktok", "username": "@ielts.practice"}, {"url": "https://tiktok.com/@ielts.practice", "label": "YouTube", "iconUrl": "/img-admin/social/youtube.svg", "platform": "youtube", "username": "@ielts.practice"}, {"url": "https://tiktok.com/@ielts.practice", "label": "Zalo", "iconUrl": "/img-admin/social/zalo.svg", "platform": "zalo", "username": "@ielts.practice"}]}', '2026-04-08 14:04:50.052+00');
INSERT INTO public.cms_configs VALUES ('dcaefbc8-1d5a-4a5e-9e8f-83e56f23c628', 'subscription/faq', '{"badge": {"text": "FAQ"}, "items": [{"answer": "Có! Bạn có thể dùng thử miễn phí với bộ CAM sau đó quyết định đăng ký để luyện kho đề Premium", "question": "Tôi có thể dùng thử miễn phí không?"}, {"answer": "Các đề thi trên web đều là đề thi thật, có tỉ lệ cao ra lại dựa trên phản hồi từ thí sinh thi gần đây.\nMục tiêu là giúp học viên làm quen dạng bài, làm trước các đề tại nhà, cách hỏi và giao diện thi máy trước ngày thi.", "question": "Đề luyện có giống đề thi thật không?"}, {"answer": "Bạn nên làm phần Full Test từ đề mới nhất trở về để bám sát xu hướng ra đề", "question": "Tôi nên làm đề nào trước?"}, {"answer": "Tài khoản Premium cho phép bạn:\n- Truy cập đầy đủ đề luyện và đề dự đoán\n- Luyện không giới hạn lượt làm bài\n- Cập nhật đề mới theo xu hướng thi thật\nPhù hợp cho học viên đang chuẩn bị thi trong thời gian ngắn 1-4 tháng.", "question": "Gói Premium khác gì so với tài khoản thường?"}, {"answer": "Chọn gói 1-2 tháng nếu bạn sắp thi\nChọn gói 4 tháng để được tặng thêm bản PDF và ôn tập trong 1 Quý\n", "question": "Tôi nên bắt đầu với gói mấy tháng"}], "title": "Câu hỏi thường gặp", "description": "Giải đáp nhanh những câu hỏi phổ biến về cách luyện đề, gói Premium và hình thức thi máy."}', '2026-04-13 14:20:17.238+00');
INSERT INTO public.cms_configs VALUES ('91e771c6-1d6b-4bd9-9f39-62975d4e44c7', 'seo/global', '{"ogImage": "", "siteTitle": "Vit IELTS — Luyện thi IELTS Online", "titleSuffix": "VIT IELTS"}', '2026-05-02 11:33:50.319+00');
INSERT INTO public.cms_configs VALUES ('dc2ef372-88cb-48a6-9048-33989ead6322', 'email-template', '{"brand": {"name": "Vit IELTS", "email": "vitielts9@gmail.com", "phone": "0927090848", "address": "", "logoUrl": "", "website": "https://vitieltstest.com"}, "style": {"textColor": "#333333", "bodyBgColor": "#f4f6f8", "primaryColor": "#D94A56", "footerBgColor": "#2D3142", "headerBgColor": "#D94A56", "contentBgColor": "#ffffff", "footerTextColor": "#ffffff", "headerBgGradient": "linear-gradient(135deg, #D94A56 0%, #c62828 100%)"}, "adminNotification": {"subject": "[Admin] Thanh toán thành công - Đơn hàng {{orderId}}", "bodyHtml": "Xác nhận đơn hàng thanh toán thành công!", "headerTitle": "Thông báo đơn hàng mới"}, "orderConfirmation": {"subject": "Thanh toán thành công - Đơn hàng {{orderId}}", "bodyHtml": "Chúc mừng bạn! Đơn hàng của bạn đã được xử lý hoàn tất. \n\nTài khoản <strong>Pro</strong> của bạn đã được kích hoạt thành công. Bạn có thể đăng nhập và bắt đầu làm bài dự đoán ngay.", "greeting": "Xin chào {{customerName}},", "ctaButton": {"link": "https://vitieltstest.com", "text": "Bắt đầu học ngay"}, "footerText": "Nếu bạn cần hỗ trợ, vui lòng liên hệ với chúng tôi qua email hoặc số điện thoại bên dưới.", "closingHtml": "Hãy nhắn qua <a href=\"https://zalo.me/0927090848\" style=\"color: #0068FF; font-weight: bold;\">Zalo 0927090848</a> để nhận trọn bộ tài liệu Writing và Speaking\n\n<i>Nếu cần hỗ trợ thêm bất cứ điều gì trong quá trình sử dụng, bạn cứ nhắn qua Zalo Nhé</i>\n<i>Chúc bạn ôn luyện thật tốt!</i>", "headerTitle": "[Vit IELTS] Tài khoản Pro của bạn đã sẵn sàng để sử dụng!", "orderTableTitle": "Tóm tắt đơn hàng"}}', '2026-04-13 15:51:40.149+00');
